      "multi.runon": "Ausführen auf", "multi.caption": "Ein Tipp → der Befehl läuft auf jeder gewählten Maschine.",
      "packs.eyebrow": "Für Communities & Macher", "packs.h2": "Button-Packs: eine ganze Einrichtung mit einem Klick teilen.",
      "packs.lead": "Ein Pack ist ein fertiges Set von Buttons für ein Tool oder einen Ablauf. Installiere eines und du bist in Sekunden bereit — kein Suchen, kein Raten. <b style='color:var(--txt)'>Alle Packs sind gratis.</b>",
      "packs.c1h": "Machst du Software, die Leute nutzen?", "packs.c1p": "Veröffentliche ein offizielles Pack für deine Software — vom Wochenend-Tool bis zur Plattform mit Millionen Nutzern. Commandeck wird zur freundlichen grafischen Schicht über deinen Befehlen und zum schnelleren Weg zu „läuft“ für alle, die sie nutzen.",
      "packs.c1li1": "Deine Befehle, für alle einen Tipp entfernt.", "packs.c1li2": "Signiert & vertrauenswürdig — Installationen von der App geprüft.", "packs.c1li3": "Gratis zu veröffentlichen, gratis für Nutzer.",
      "packs.c2h": "Hast du ein praktisches Button-Set?", "packs.c2p": "Exportiere deine Buttons als Pack und reiche es auf GitHub ein. Nach Prüfung und Signatur erscheint es für alle in der In-App-Galerie.",
      "packs.c2li1": "Export in eine teilbare Pack-Datei — gratis.", "packs.c2li2": "Einreichung per Pull Request auf GitHub — keine App-Anmeldung.", "packs.c2li3": "Hilf anderen, die Einrichtung zu überspringen, die du schon gelöst hast.",
      "packs.cta1": "Packs durchstöbern", "packs.cta2": "Pack erstellen & einreichen →",
      "per.eyebrow": "Für dich gemacht", "per.h2": "Wenn das dein Setup ist, bist du zu Hause.",
      "per.c1": "Du hast einen <b style='color:var(--txt)'>Heimserver</b> — ein NAS, Mini-PC, Proxmox oder Docker — mit einer Maschine oder dreien.",
      "per.c2": "Du hast ihn <b style='color:var(--txt)'>mit einer KI als Tutor</b> eingerichtet und lebst lieber nicht im Terminal.",
      "per.c3": "Du kommst mit Windows oder Mac klar, aber <b style='color:var(--txt)'>die Kommandozeile ist nicht dein Ding</b>.",
      "per.c4": "Du willst deine wichtigen Befehle <b style='color:var(--txt)'>gespeichert und einen Tipp entfernt</b> — auf einer Maschine oder mehreren.",
      "price.eyebrow": "Einfacher Preis", "price.h2": "Einmal kaufen. Für immer deins.", "price.lead": "Kein Abo. Keine Verlängerung. Teste alles 14 Tage gratis.",
      "price.free.name": "Gratis", "price.free.desc": "Befehle auf diesem Rechner ausführen. Für immer.",
      "price.free.li1": "Unbegrenzte Buttons auf deinem PC", "price.free.li2": "Alle Icons & Farben", "price.free.li3": "Kein Konto, komplett privat", "price.free.li4": "Jederzeit auf SSH upgraden", "price.free.btn": "Gratis herunterladen",
      "price.pop": "Am beliebtesten", "price.desk.name": "Desktop", "price.once": "einmalig", "price.desk.desc": "Windows, macOS & Linux. Lebenslang.",
      "price.desk.li1": "Alles aus Gratis", "price.desk.li2": "SSH zu all deinen Maschinen", "price.desk.li3": "Ausführung auf mehreren Maschinen", "price.desk.li4": "Eigene Themes, Backup & mehr", "price.desk.btn": "14-Tage-Test starten",
      "price.desk.buy": buy("oder", "Lizenz kaufen", "— in der App aktivieren"),
      "price.soon": "Bald", "price.and.name": "Android", "price.and.desc": "Deine Buttons in der Tasche. In Vorbereitung.",
      "price.and.li1": "Das volle Button-Raster, mobil", "price.and.li2": "Sicheres SSH zu deinen Maschinen", "price.and.li3": "Einmalpreis, kein Abo", "price.and.li4": "Lokales Backup & Wiederherstellung", "price.and.btn": "Bald",
      "final.h2": "Schluss mit Suchen. Einfach tippen.", "final.lead": "Die Befehle, auf die du zählst — gespeichert, sortiert, einen Tipp entfernt.", "final.cta": "Download — 14 Tage Pro gratis testen →",
      "bug.eyebrow": "Etwas kaputt?", "bug.h2": "Fehler melden", "bug.lead": "Etwas läuft nicht wie es soll? Sag uns Bescheid — dauert eine Minute und macht Commandeck für alle besser.", "bug.cta": "Fehler auf GitHub melden →",
