      "nav.how": "Como funciona", "nav.features": "Recursos", "nav.packs": "Packs", "nav.pricing": "Preços", "nav.docs": "Docs", "nav.download": "Baixar",
      "hero.pill": "Privado por design — nada sai do seu dispositivo",
